namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string text, int maxSentences);
}

/// <summary>
/// Extractive summarizer that scores sentences by word frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords =
    [
        "the", "a", "an", "is", "are", "was", "were", "be", "been", "being",
        "have", "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "shall", "can", "to", "of", "in", "for",
        "on", "with", "at", "by", "from", "as", "into", "through", "during",
        "before", "after", "and", "but", "or", "nor", "not", "so", "yet",
        "both", "either", "neither", "each", "every", "all", "any", "few",
        "more", "most", "other", "some", "such", "no", "only", "own", "same",
        "than", "too", "very", "just", "because", "this", "that", "these",
        "those", "it", "its", "he", "she", "they", "them", "his", "her",
        "their", "we", "our", "you", "your", "i", "me", "my", "about"
    ];

    public string Summarize(string text, int maxSentences)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(text);
        ArgumentOutOfRangeException.ThrowIfLessThan(maxSentences, 1);

        var sentences = SplitSentences(text);
        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((sentence, index) => (Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => sentences[s.Index]);

        return string.Join(" ", scored);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text.Trim())
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word.ToLowerInvariant()))
                {
                    var lower = word.ToLowerInvariant();
                    frequencies[lower] = frequencies.GetValueOrDefault(lower) + 1;
                }
            }
        }
        return frequencies;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> frequencies)
    {
        var words = ExtractWords(sentence);
        if (words.Count == 0) return 0;

        double score = words
            .Where(w => !StopWords.Contains(w.ToLowerInvariant()))
            .Sum(w => frequencies.GetValueOrDefault(w.ToLowerInvariant()));

        return score / words.Count;
    }

    private static List<string> ExtractWords(string text)
    {
        return WordRegex().Matches(text).Select(m => m.Value).ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z']+\b")]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Text))
            return BadRequest(new { error = "Text is required and must not be empty." });

        var summary = summarizer.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.Text.Length,
            SummaryLength = summary.Length
        });
    }
}

